// // This module implements a 2-to-4 binary decoder with an active high enable input. The decoder converts the 2-bit binary input to a 4-bit one-hot output when the enable signal is high. If the enable signal is low, all outputs should be zero.
module decoder_2to4(
    input enable_n,
    input [1:0] d,
    output reg [3:0] y
);

always @(*) begin
    if (!enable_n)
        y = 4'b0001 << d;
    else
        y = 4'b0000;
end

endmodule
